export const getGetHighlightQueryKey = (highlightId: string) => {
  return [`/api/highlights/${highlightId}`] as const;
};

export const getGetHighlightQueryOptions = <
  TData = Awaited<ReturnType<typeof getHighlight>>,
  TError = ErrorType<unknown>,
>(
  highlightId: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getHighlight>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetHighlightQueryKey(highlightId);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getHighlight>>> = ({
    signal,
  }) => getHighlight(highlightId, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!highlightId,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getHighlight>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

